import { render, screen } from '@testing-library/react'
import { MainLayout } from './MainLayout'
import { useAuthStore, UserRole } from '@/store/authStore'
import { useRouter } from 'next/navigation'
import fc from 'fast-check'

// Mock dependencies
jest.mock('@/store/authStore')
jest.mock('next/navigation')
jest.mock('framer-motion', () => ({
  motion: {
    div: ({ children, ...props }: any) => <div {...props}>{children}</div>
  }
}))

const mockUseAuthStore = useAuthStore as jest.MockedFunction<typeof useAuthStore>
const mockUseRouter = useRouter as jest.MockedFunction<typeof useRouter>

const mockRouter = {
  push: jest.fn(),
  back: jest.fn(),
  forward: jest.fn(),
  refresh: jest.fn(),
  replace: jest.fn(),
  prefetch: jest.fn()
}

describe('MainLayout Navigation', () => {
  beforeEach(() => {
    jest.clearAllMocks()
    mockUseRouter.mockReturnValue(mockRouter as any)
  })

  // Feature: critical-thinking-network, Property 43: Role-based navigation
  describe('Property 43: Role-based navigation', () => {
    it('should display appropriate navigation options based on user role', () => {
      fc.assert(
        fc.property(
          fc.record({
            userId: fc.uuid(),
            username: fc.string({ minLength: 3, maxLength: 30 }).filter(s => /^[a-zA-Z0-9_-]+$/.test(s)),
            email: fc.emailAddress(),
            role: fc.constantFrom(
              UserRole.GUEST,
              UserRole.GENERAL_USER, 
              UserRole.COLLEGE_USER,
              UserRole.MODERATOR,
              UserRole.ADMIN
            ),
            collegeId: fc.option(fc.uuid(), { nil: undefined }),
            isAuthenticated: fc.boolean()
          }),
          (testData) => {
            // Mock the auth store based on test data
            const mockUser = testData.isAuthenticated ? {
              id: testData.userId,
              username: testData.username,
              email: testData.email,
              role: testData.role,
              collegeId: testData.collegeId,
              createdAt: new Date()
            } : null

            mockUseAuthStore.mockReturnValue({
              user: mockUser,
              token: testData.isAuthenticated ? 'mock-token' : null,
              college: null,
              isAuthenticated: testData.isAuthenticated,
              isLoading: false,
              setUser: jest.fn(),
              setToken: jest.fn(),
              setCollege: jest.fn(),
              logout: jest.fn(),
              setLoading: jest.fn()
            })

            // Render the component
            render(
              <MainLayout>
                <div>Test Content</div>
              </MainLayout>
            )

            // Verify navigation items based on role
            const feedLink = screen.queryByText('Feed')
            const collegeLink = screen.queryByText('College')
            const resourcesLink = screen.queryByText('Resources')
            const moderatorLink = screen.queryByText('Moderator')
            const adminLink = screen.queryByText('Admin')
            const searchLink = screen.queryByText('Search')

            // Feed should always be visible
            expect(feedLink).toBeInTheDocument()

            if (!testData.isAuthenticated) {
              // Guest users should not see authenticated-only features
              expect(searchLink).not.toBeInTheDocument()
              expect(collegeLink).not.toBeInTheDocument()
              expect(resourcesLink).not.toBeInTheDocument()
              expect(moderatorLink).not.toBeInTheDocument()
              expect(adminLink).not.toBeInTheDocument()
            } else {
              // Authenticated users should see search
              expect(searchLink).toBeInTheDocument()

              // Role-specific navigation
              switch (testData.role) {
                case UserRole.GUEST:
                  expect(collegeLink).not.toBeInTheDocument()
                  expect(resourcesLink).not.toBeInTheDocument()
                  expect(moderatorLink).not.toBeInTheDocument()
                  expect(adminLink).not.toBeInTheDocument()
                  break

                case UserRole.GENERAL_USER:
                  expect(collegeLink).not.toBeInTheDocument()
                  expect(resourcesLink).not.toBeInTheDocument()
                  expect(moderatorLink).not.toBeInTheDocument()
                  expect(adminLink).not.toBeInTheDocument()
                  break

                case UserRole.COLLEGE_USER:
                  expect(collegeLink).toBeInTheDocument()
                  expect(resourcesLink).toBeInTheDocument()
                  expect(moderatorLink).not.toBeInTheDocument()
                  expect(adminLink).not.toBeInTheDocument()
                  break

                case UserRole.MODERATOR:
                  expect(collegeLink).toBeInTheDocument()
                  expect(resourcesLink).toBeInTheDocument()
                  expect(moderatorLink).toBeInTheDocument()
                  expect(adminLink).not.toBeInTheDocument()
                  break

                case UserRole.ADMIN:
                  expect(collegeLink).toBeInTheDocument()
                  expect(resourcesLink).toBeInTheDocument()
                  expect(moderatorLink).toBeInTheDocument()
                  expect(adminLink).toBeInTheDocument()
                  break
              }
            }
          }
        ),
        { numRuns: 5 }
      )
    })

    it('should show login button for unauthenticated users', () => {
      fc.assert(
        fc.property(
          fc.constant(null), // No user
          () => {
            mockUseAuthStore.mockReturnValue({
              user: null,
              token: null,
              college: null,
              isAuthenticated: false,
              isLoading: false,
              setUser: jest.fn(),
              setToken: jest.fn(),
              setCollege: jest.fn(),
              logout: jest.fn(),
              setLoading: jest.fn()
            })

            render(
              <MainLayout>
                <div>Test Content</div>
              </MainLayout>
            )

            // Should show sign in button for unauthenticated users
            const signInButton = screen.getByText('Sign In')
            expect(signInButton).toBeInTheDocument()

            // Should not show user dropdown
            const userDropdown = screen.queryByText('@')
            expect(userDropdown).not.toBeInTheDocument()
          }
        ),
        { numRuns: 3 }
      )
    })

    it('should show user dropdown for authenticated users', () => {
      fc.assert(
        fc.property(
          fc.record({
            userId: fc.uuid(),
            username: fc.string({ minLength: 3, maxLength: 30 }).filter(s => /^[a-zA-Z0-9_-]+$/.test(s)),
            email: fc.emailAddress(),
            role: fc.constantFrom(UserRole.GENERAL_USER, UserRole.COLLEGE_USER, UserRole.MODERATOR, UserRole.ADMIN)
          }),
          (testData) => {
            const mockUser = {
              id: testData.userId,
              username: testData.username,
              email: testData.email,
              role: testData.role,
              createdAt: new Date()
            }

            mockUseAuthStore.mockReturnValue({
              user: mockUser,
              token: 'mock-token',
              college: null,
              isAuthenticated: true,
              isLoading: false,
              setUser: jest.fn(),
              setToken: jest.fn(),
              setCollege: jest.fn(),
              logout: jest.fn(),
              setLoading: jest.fn()
            })

            render(
              <MainLayout>
                <div>Test Content</div>
              </MainLayout>
            )

            // Should show user initial in dropdown
            const userInitial = screen.getByText(testData.username[0].toUpperCase())
            expect(userInitial).toBeInTheDocument()

            // Should not show sign in button
            const signInButton = screen.queryByText('Sign In')
            expect(signInButton).not.toBeInTheDocument()
          }
        ),
        { numRuns: 5 }
      )
    })
  })

  // Unit tests for specific scenarios
  describe('Specific navigation scenarios', () => {
    it('should show all navigation items for admin users', () => {
      const mockAdmin = {
        id: 'admin-id',
        username: 'admin',
        email: 'admin@example.com',
        role: UserRole.ADMIN,
        createdAt: new Date()
      }

      mockUseAuthStore.mockReturnValue({
        user: mockAdmin,
        token: 'mock-token',
        college: null,
        isAuthenticated: true,
        isLoading: false,
        setUser: jest.fn(),
        setToken: jest.fn(),
        setCollege: jest.fn(),
        logout: jest.fn(),
        setLoading: jest.fn()
      })

      render(
        <MainLayout>
          <div>Test Content</div>
        </MainLayout>
      )

      // Admin should see all navigation items
      expect(screen.getByText('Feed')).toBeInTheDocument()
      expect(screen.getByText('College')).toBeInTheDocument()
      expect(screen.getByText('Resources')).toBeInTheDocument()
      expect(screen.getByText('Moderator')).toBeInTheDocument()
      expect(screen.getByText('Admin')).toBeInTheDocument()
      expect(screen.getByText('Search')).toBeInTheDocument()
    })

    it('should show limited navigation for general users', () => {
      const mockGeneralUser = {
        id: 'user-id',
        username: 'generaluser',
        email: 'user@gmail.com',
        role: UserRole.GENERAL_USER,
        createdAt: new Date()
      }

      mockUseAuthStore.mockReturnValue({
        user: mockGeneralUser,
        token: 'mock-token',
        college: null,
        isAuthenticated: true,
        isLoading: false,
        setUser: jest.fn(),
        setToken: jest.fn(),
        setCollege: jest.fn(),
        logout: jest.fn(),
        setLoading: jest.fn()
      })

      render(
        <MainLayout>
          <div>Test Content</div>
        </MainLayout>
      )

      // General user should see limited navigation
      expect(screen.getByText('Feed')).toBeInTheDocument()
      expect(screen.getByText('Search')).toBeInTheDocument()
      
      // Should not see college-specific features
      expect(screen.queryByText('College')).not.toBeInTheDocument()
      expect(screen.queryByText('Resources')).not.toBeInTheDocument()
      expect(screen.queryByText('Moderator')).not.toBeInTheDocument()
      expect(screen.queryByText('Admin')).not.toBeInTheDocument()
    })
  })
})
